1	// COR24 APL Interpreter -- Array Data Structure
2	// Bump-allocated heap with rank/shape headers.
3	// Supports rank 0 (scalar), rank 1 (vector), rank 2 (matrix).
4	//
5	// Heap layout per array:
6	//   [idx+0] = rank  (0, 1, or 2)
7	//   [idx+1] = dim0  (length for vectors, rows for matrices)
8	//   [idx+2] = dim1  (cols for matrices, 0 otherwise)
9	//   [idx+3..] = data elements
10	
11	#pragma once
12	
13	#define HEAP_SIZE 4096
14	#define ARR_HDR   3
15	
16	int heap[HEAP_SIZE];
17	int heap_top;
18	
19	// Reset heap (reclaim all arrays)
20	void arr_reset() {
21	    heap_top = 0;
22	}
23	
24	// Allocate array. Returns heap index, or -1 if full.
25	// For rank 0: dim0=1, dim1=0 (one scalar element)
26	// For rank 1: dim0=length, dim1=0
27	// For rank 2: dim0=rows, dim1=cols
28	int arr_new(int rank, int dim0, int dim1) {
29	    int size;
30	    if (rank <= 1) {
31	        size = dim0;
32	    } else {
33	        size = dim0 * dim1;
34	    }
35	    int need = ARR_HDR + size;
36	    if (heap_top + need > HEAP_SIZE) return -1;
37	
38	    int idx = heap_top;
39	    heap[idx]     = rank;
40	    heap[idx + 1] = dim0;
41	    heap[idx + 2] = dim1;
42	    heap_top = heap_top + need;
43	
44	    // Zero-fill data
45	    int i = 0;
46	    while (i < size) {
47	        heap[idx + ARR_HDR + i] = 0;
48	        i++;
49	    }
50	    return idx;
51	}
52	
53	// Accessors
54	int arr_rank(int idx) { return heap[idx]; }
55	int arr_dim0(int idx) { return heap[idx + 1]; }
56	int arr_dim1(int idx) { return heap[idx + 2]; }
57	
58	// Total element count
59	int arr_size(int idx) {
60	    if (heap[idx] <= 1) return heap[idx + 1];
61	    return heap[idx + 1] * heap[idx + 2];
62	}
63	
64	// Get/set data element by flat index
65	int arr_get(int idx, int i) {
66	    return heap[idx + ARR_HDR + i];
67	}
68	
69	void arr_set(int idx, int i, int val) {
70	    heap[idx + ARR_HDR + i] = val;
71	}
72	
73	// Create a scalar array holding one value
74	int arr_scalar(int val) {
75	    int idx = arr_new(0, 1, 0);
76	    if (idx < 0) return -1;
77	    arr_set(idx, 0, val);
78	    return idx;
79	}
80	
81	// Create a vector from inline values (up to count elements)
82	int arr_vector(int count) {
83	    return arr_new(1, count, 0);
84	}
85

